  ('pukao-0c700c30-moex-00124', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '小鳳可以在30分鐘內煮好晚餐，在20分鐘內洗好衣服。他的室友做這兩件工作都只需花一半的時間。兩人 應如何分配工作？', '["小鳳應多煮晚餐", "小鳳應多洗衣服", "這兩件工作兩人平均分擔", "兩人不會有交易利得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00125', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '下列何種市場中廠商是需求者？', '["水果市場", "稻米市場", "勞動市場", "電子遊戲市場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00126', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '沿生產可能曲線生產商品和服務時，存在權衡是因為：', '["並非所有生產都是有效的", "人的慾望和需求是無限的", "買賣雙方經常須協商價格", "社會只有有限的生產資源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00127', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '關於供給價格彈性的敘述，下列何者正確？', '["當一產品的原物料不容易取得，此產品供給的價格彈性將較不敏感", "當供給的價格彈性較需求的價格彈性不敏感，針對商品所課的稅將較容易被轉嫁給消費者", "當一產品的原物料擁有顯著的規模經濟，此產品供給的價格彈性將較不敏感", "當計程車數量達到政府許可滿額時，其供給的價格彈性將為無限大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00128', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '給定貢丸的市場需求函數Q =22–3P+0.2P，其中Q 為貢丸的需求量，P為貢丸的市場價格，P為魚丸的 D F D F 市場價格。根據這些資訊，下列敘述何者正確？', '["貢丸屬於豬肉製品，魚丸屬於魚肉製品，此需求曲線印證了此二產品彼此需求並不相關", "若是魚丸的價格上升1個百分點，貢丸的需求量會上升0.2個百分點", "對消費者而言，貢丸和魚丸是互補品", "貢丸的需求滿足「需求法則」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00129', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在完全競爭市場中，當廠商生產產品的數量等於市場均衡數量時，下列敘述何者錯誤？', '["生產最後一個單位產品的邊際收益等於邊際成本", "消費者的剩餘和生產者的剩餘被極大化", "資源被有效的運用在生產過程中", "廠商繼續生產下一單位產品仍可獲利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00130', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '魯濱遜在荒島上，他每小時可摘10個椰子或抓1條魚。他的朋友每小時可摘30個椰子或抓2條魚。下列敘述 何者正確？', '["以抓魚而言，魯濱遜具有絕對利益", "以抓魚而言，魯濱遜具有比較利益", "以摘椰子而言，魯濱遜具有絕對利益", "以摘椰子而言，魯濱遜具有比較利益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00131', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '張三的所得剛好消費甲商品2單位與乙商品10單位；或是剛好消費甲商品4單位與乙商品2單位。若張三將 其所得全部消費於乙商品，則可購買多少單位的乙商品？', '["12單位", "14單位", "16單位", "18單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00132', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '營建業工人的工資上升將導致新房屋市場的：', '["需求曲線整條向右移動", "需求曲線整條向左移動", "供給曲線整條向右移動", "供給曲線整條向左移動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
